#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 800000
#define MAX_M 200000
#define MAX_HEIGHT 10000

// Segment tree node structure
typedef struct {
    int height;
    int force;
} Node;

// Function to create a new segment tree node
Node* createNode(int height) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->height = height;
    node->force = 0;
    return node;
}

// Function to update the segment tree
void update(Node** tree, int node, int start, int end, int left, int right, int force) {
    if (start > right || end < left) return;
    if (start >= left && end <= right) {
        tree[node]->force += force;
        return;
    }
    int mid = (start + end) / 2;
    update(tree, 2 * node, start, mid, left, right, force);
    update(tree, 2 * node + 1, mid + 1, end, left, right, force);
}

// Function to query the segment tree
int query(Node** tree, int node, int start, int end, int left, int right) {
    if (start > right || end < left) return 0;
    if (start >= left && end <= right) {
        int height = tree[node]->height;
        int force = tree[node]->force;
        char str[5];
        sprintf(str, "%04d", height);
        char newStr[5];
        for (int i = 0; i < 4; i++) {
            newStr[(i + force) % 4] = str[i];
        }
        return atoi(newStr);
    }
    int mid = (start + end) / 2;
    int leftMax = query(tree, 2 * node, start, mid, left, right);
    int rightMax = query(tree, 2 * node + 1, mid + 1, end, left, right);
    return (leftMax > rightMax) ? leftMax : rightMax;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node** tree = (Node**) malloc(4 * N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            int height;
            scanf("%d", &height);
            tree[i] = createNode(height);
        }
        int M;
        scanf("%d", &M);
        for (int i = 0; i < M; i++) {
            int type;
            scanf("%d", &type);
            if (type == 0) {
                int left, right, force;
                scanf("%d %d %d", &left, &right, &force);
                update(tree, 1, 0, N - 1, left, right, force);
            } else {
                int left, right;
                scanf("%d %d", &left, &right);
                int max = query(tree, 1, 0, N - 1, left, right);
                printf("%d\n", max);
            }
        }
    }
    return 0;
}

