let idx = 0;

class Node {
    constructor(height) {
        this.height = height;
        this.force = 0;
    }
}

function update(tree, node, start, end, left, right, force) {
    if (start > right || end < left) return;
    if (start >= left && end <= right) {
        tree[node].force += force;
        return;
    }
    const mid = Math.floor((start + end) / 2);
    update(tree, 2 * node, start, mid, left, right, force);
    update(tree, 2 * node + 1, mid + 1, end, left, right, force);
}

function query(tree, node, start, end, left, right) {
    if (start > right || end < left) return 0;
    if (start >= left && end <= right) {
        let height = tree[node].height;
        let force = tree[node].force;
        let str = height.toString().padStart(4, '0');
        let newStr = '';
        for (let i = 0; i < 4; i++) {
            newStr += str[(i + force) % 4];
        }
        return parseInt(newStr);
    }
    const mid = Math.floor((start + end) / 2);
    const leftMax = query(tree, 2 * node, start, mid, left, right);
    const rightMax = query(tree, 2 * node + 1, mid + 1, end, left, right);
    return Math.max(leftMax, rightMax);
}

